   ('CLN-Q0089','سوبر تاول مغلف سانيتا 150م، شد 24','أدوات التنظيف', 51,'كرتون','شركة العوبثاني الأولى للتجارة', DATE '2026-06-03','1307',NULL),
   ('CLN-Q0090','اسفنج الفا برايت C2 (3+6 مجانًا)، شد 20','أدوات التنظيف', 5,'ربطة','شركة العوبثاني الأولى للتجارة', DATE '2026-06-03','1307',NULL),
